code = """import json
import pandas as pd
from datetime import datetime

# Data from support database for last 4 quarters (2022-04-01 to 2023-04-10)
# This is stored directly in locals() under the variable name `var_functions.query_db_36`
# Let's access it properly
data = locals()['var_functions.query_db_36']

# Count transfers per agent and cases handled per agent
transfers_from_agent = {}
cases_handled_by_agent = {}

for record in data:
    old_agent = record['oldvalue__c']
    new_agent = record['newvalue__c']
    
    # Track cases handled (when agent receives a case)
    if new_agent != 'None':
        cases_handled_by_agent[new_agent] = cases_handled_by_agent.get(new_agent, 0) + 1
    
    # Track transfer counts (when agent transfers a case away)
    if old_agent != 'None':
        transfers_from_agent[old_agent] = transfers_from_agent.get(old_agent, 0) + 1

# Filter: agents who handled more than 0 cases
eligible_agents = {}
for agent in cases_handled_by_agent:
    if cases_handled_by_agent[agent] > 0:
        eligible_agents[agent] = {
            'case_count': cases_handled_by_agent[agent],
            'transfer_count': transfers_from_agent.get(agent, 0)
        }

# Find agent with minimum transfer count (tie-break by agent ID)
if eligible_agents:
    sorted_agents = sorted(eligible_agents.items(), key=lambda x: (x[1]['transfer_count'], x[0]))
    min_agent = sorted_agents[0][0]
    min_stats = sorted_agents[0][1]
    
    print(f"Agent with minimum transfers: {min_agent}")
    print(f"Cases handled: {min_stats['case_count']}, Transfers: {min_stats['transfer_count']}")
    
    # Show top 5 for verification
    print("\nTop 5 agents with fewest transfers:")
    for i, (agent, stats) in enumerate(sorted_agents[:5]):
        print(f"{i+1}. {agent}: {stats['case_count']} cases, {stats['transfer_count']} transfers")
else:
    min_agent = None
    print("No eligible agents found")

# Return result in required format
print("__RESULT__:")
print(json.dumps(min_agent))"""

